}

bool operator<(const RoutePt& p1, const RoutePt& p2)
{
  return (p1._x < p2._x) || (p1._x == p2._x && p1._y < p2._y)
         || (p1._x == p2._x && p1._y == p2._y && p1._layer < p2._layer);
}

