  for (int i = 0; i < num_nets_; i++)
    nets_[i] = new FrNet;
  seglist_index_.resize(num_nets_ + 1);
}

void FastRouteCore::setLowerLeft(int x, int y)
{
  x_corner_ = x;
  y_corner_ = y;
}

