int FastRouteCore::getEdgeCurrentResource(long x1,
                                          long y1,
                                          int l1,
                                          long x2,
                                          long y2,
                                          int l2)
{
  int grid, k;
  int resource = 0;

  k = l1 - 1;
  if (y1 == y2) {
    grid = y1 * (x_grid_ - 1) + x1 + k * (x_grid_ - 1) * y_grid_;
    resource = h_edges_3D_[grid].cap - h_edges_3D_[grid].usage;
  } else if (x1 == x2) {
    grid = y1 * x_grid_ + x1 + k * x_grid_ * (y_grid_ - 1);
