void FastRouteCore::printEdge(int netID, int edgeID)
{
  int i;
  TreeEdge edge;
  TreeNode* nodes;

  edge = sttrees_[netID].edges[edgeID];
  nodes = sttrees_[netID].nodes;

  logger_->report("edge {}: ({}, {})->({}, {})",
                 edgeID,
                 nodes[edge.n1].x,
                 nodes[edge.n1].y,
                 nodes[edge.n2].x,
                 nodes[edge.n2].y);
