#if LUT_SOURCE==LUT_FILE || LUT_SOURCE==LUT_VAR_CHECK
static void
readLUTfiles(LUT_TYPE LUT,
	     NUMSOLN_TYPE numsoln) {
  unsigned char charnum[256], line[32], *linep, c;
  FILE *fpwv, *fprt;
  struct csoln *p;
  int d, i, j, k, kk, ns, nn;

  for (i = 0; i <= 255; i++) {
    if ('0' <= i && i <= '9')
      charnum[i] = i - '0';
    else if (i >= 'A')
      charnum[i] = i - 'A' + 10;
    else  // if (i=='$' || i=='\n' || ... )
      charnum[i] = 0;
  }

  fpwv = fopen(FLUTE_POWVFILE, "r");
  if (fpwv == NULL) {
    printf("Error in opening %s\n", FLUTE_POWVFILE);
    exit(1);
  }

#if FLUTE_ROUTING == 1
  fprt = fopen(FLUTE_POSTFILE, "r");
  if (fprt == NULL) {
    printf("Error in opening %s\n", FLUTE_POSTFILE);
    exit(1);
  }
#endif

  for (d = 4; d <= FLUTE_D; d++) {
    fscanf(fpwv, "d=%d", &d);
    fgetc(fpwv);    // '/n'
#if FLUTE_ROUTING == 1
    fscanf(fprt, "d=%d", &d);
    fgetc(fprt);    // '/n'
#endif
    for (k = 0; k < numgrp[d]; k++) {
      ns = (int)charnum[fgetc(fpwv)];

      if (ns == 0) {  // same as some previous group
        fscanf(fpwv, "%d", &kk);
        fgetc(fpwv); // '/n'
        numsoln[d][k] = numsoln[d][kk];
        LUT[d][k] = LUT[d][kk];
      } else {
        fgetc(fpwv);  // '\n'
        numsoln[d][k] = ns;
        p = (struct csoln *)malloc(ns * sizeof(struct csoln));
        LUT[d][k] = p;
        for (i = 1; i <= ns; i++) {
          linep = (unsigned char *)fgets((char *)line, 32, fpwv);
          p->parent = charnum[*(linep++)];
          j = 0;
          while ((p->seg[j++] = charnum[*(linep++)]) != 0)
            ;
          j = 10;
          while ((p->seg[j--] = charnum[*(linep++)]) != 0)
            ;
#if FLUTE_ROUTING == 1
          nn = 2 * d - 2;
          fread(line, 1, d - 2, fprt);
          linep = line;
          for (j = d; j < nn; j++) {
            c = charnum[*(linep++)];
            p->rowcol[j - d] = c;
          }
          fread(line, 1, nn / 2 + 1, fprt);
          linep = line;  // last char \n
          for (j = 0; j < nn;) {
            c = *(linep++);
            p->neighbor[j++] = c / 16;
            p->neighbor[j++] = c % 16;
          }
#endif
          p++;
        }
      }
    }
  }
  fclose(fpwv);
#if FLUTE_ROUTING == 1
  fclose(fprt);
#endif
}
#endif

